function maxConsecutiveRobots(chargeTimes, runningCosts, budget) {
    const n = chargeTimes.length;
    let maxRobots = 0;
    for (let i = 0; i < n; i++) {
        let maxCharge = 0;
        let runningSum = 0;
        for (let j = i; j < n; j++) {
            maxCharge = Math.max(maxCharge, chargeTimes[j]);
            runningSum += runningCosts[j];
            const cost = maxCharge + runningSum * (j - i + 1);
            if (cost <= budget)
                maxRobots = Math.max(maxRobots, j - i + 1);
            else
                break;
        }
    }
    return maxRobots;
}
```

    1. Initialize `maxRobots` as 0
2. Iterate from the first robot to the last robot as the starting point (`i`)
3. Initialize `maxCharge` as 0 (to store the maximum charge cost) and `runningSum` as 0 (to store the sum of running costs)
4. Iterate from the starting point robot to the last robot (`j`)
5. Update `maxCharge` and `runningSum`
6. Calculate the total cost (`cost`) by `maxCharge + runningSum * (j - i + 1)`
7. If the total cost is less than or equal to the budget, update `maxRobots` as the maximum of `maxRobots` and `j - i + 1`
8. If the total cost exceeds the budget, break the inner loop
9. Continue the outer loop
10. Return `maxRobots` as the maximum number of consecutive robots that can be run within the budget.

